#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Automatic Environment Detection
 *
 * Description: Let the SDK automatically detect the best authentication method
 * based on the environment. This is the recommended approach for most applications.
 *
 * The SDK tries authentication methods in this order:
 * 1. Explicit configuration (host, token, clientId, etc.)
 * 2. Environment variables (DATABRICKS_*)
 * 3. Configuration file (~/.databrickscfg)
 * 4. Cloud provider authentication (Azure CLI, GCP default, AWS instance profile)
 *
 * Prerequisites:
 * - At least one authentication method configured
 *
 * Setup:
 * Set any of the following:
 * - Environment variables (DATABRICKS_HOST, DATABRICKS_TOKEN, etc.)
 * - Config file: ~/.databrickscfg
 * - Cloud provider authentication (az login, gcloud auth, etc.)
 *
 * Run:
 * ```bash
 * # With environment variables
 * DATABRICKS_HOST="https://your-workspace.cloud.databricks.com" \
 * DATABRICKS_TOKEN="dapi..." \
 * npx ts-node examples/auth/environment-detection.ts
 *
 * # Or just rely on config file or cloud provider auth
 * npx ts-node examples/auth/environment-detection.ts
 * ```
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    // SDK automatically detects the best authentication method
    const client = new WorkspaceClient({});

    try {
        const user = await client.currentUser.me();
        console.log(`✓ Successfully authenticated as: ${user.userName}`);
        console.log(`  User ID: ${user.id}`);

        console.log(`  Host: ${client.config.host}`);

        // Show which authentication type was detected
        if (client.config.authType) {
            console.log(`  Auth type: ${client.config.authType}`);
        }

        // Show configuration source
        console.log("\nConfiguration source:");
        if (process.env.DATABRICKS_TOKEN) {
            console.log("  - Using DATABRICKS_TOKEN from environment");
        } else if (process.env.DATABRICKS_CLIENT_ID) {
            console.log("  - Using OAuth from environment");
        } else {
            console.log(
                "  - Using config file or cloud provider authentication"
            );
        }
    } catch (error) {
        console.error("✗ Authentication failed:", error);
        console.error(
            "\nThe SDK could not detect valid credentials. Please set up one of:"
        );
        console.error("\n1. Environment variables:");
        console.error("   export DATABRICKS_HOST=<your-workspace-url>");
        console.error("   export DATABRICKS_TOKEN=<your-token>");
        console.error("\n2. Configuration file (~/.databrickscfg):");
        console.error("   [DEFAULT]");
        console.error("   host = <your-workspace-url>");
        console.error("   token = <your-token>");
        console.error("\n3. Cloud provider authentication:");
        console.error("   - Azure: az login");
        console.error("   - GCP: gcloud auth application-default login");
        console.error("   - AWS: Use EC2 instance profile");
        process.exit(1);
    }
}

main().catch(console.error);
